module pcie_fsm (
    input wire clk,
    input wire rst,
    input wire start,
    input wire ack,
    output reg [1:0] state
);
    parameter IDLE = 2'b00;
    parameter REQUEST = 2'b01;
    parameter RESPONSE = 2'b10;
    parameter RESPONSE_DELAY = 3; // Number of clock cycles to stay in RESPONSE state

    reg [1:0] obf_next_state;
    reg [1:0] response_counter;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            response_counter <= 0;
        end else begin
            state <= obf_next_state;
            if (state == RESPONSE) begin
                if (response_counter < RESPONSE_DELAY)
                    response_counter <= response_counter + 1;
                else
                    response_counter <= 0; // Reset counter after delay
            end
        end
    end

    always @(*) begin
        case (state)
            IDLE: begin
                if (start) 
                    obf_next_state = REQUEST;
                else 
                    obf_next_state = IDLE;
            end
            REQUEST: begin
                if (ack) 
                    obf_next_state = RESPONSE;
                else 
                    obf_next_state = REQUEST;
            end
            RESPONSE: begin
                if (response_counter == RESPONSE_DELAY)
                    obf_next_state = IDLE;
                else 
                    obf_next_state = RESPONSE;
            end
            default: obf_next_state = IDLE;
        endcase
    end
endmodule
